import React, { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Polyline, Marker } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import gpsData from './frontend_data_gps.json';
import './App.scss'; // Importa o CSS acima

// Fix do ícone
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png',
});

const App = () => {
  const [selectedCourse, setSelectedCourse] = useState(0);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);

  const vehicle = gpsData.vehicle;
  const courses = gpsData.courses || [];
  const currentCourse = courses[selectedCourse];
  const points = currentCourse?.gps || [];
  const currentPoint = points[currentIndex];

  // Animação
  useEffect(() => {
    if (!isPlaying) return;
    
    const interval = setInterval(() => {
      setCurrentIndex(prev => {
        if (prev >= points.length - 1) {
          setIsPlaying(false);
          return prev;
        }
        return prev + 1;
      });
    }, 500);

    return () => clearInterval(interval);
  }, [isPlaying, points.length]);

  return (
    <div className="app-container">
      <header style={{ padding: '1rem', background: '#333', color: '#fff' }}>
        <h1>🚗 Rastreamento 3D</h1>
        <div>
          <select 
            value={selectedCourse} 
            onChange={(e) => {
              setSelectedCourse(Number(e.target.value));
              setCurrentIndex(0);
              setIsPlaying(false);
            }}
          >
            {courses.map((_, i) => (
              <option key={i} value={i}>Rota {i + 1}</option>
            ))}
          </select>
          <button onClick={() => setIsPlaying(!isPlaying)}>
            {isPlaying ? '⏸ Pausar' : '▶ Play'}
          </button>
          <button onClick={() => { setCurrentIndex(0); setIsPlaying(false); }}>
            🔄 Reiniciar
          </button>
        </div>
      </header>

      {/* MAPA COM ALTURA EXPLÍCITA */}
      <div className="map-wrapper" style={{ height: '600px', width: '100%' }}>
        <MapContainer 
          center={points[0] ? [points[0].latitude, points[0].longitude] : [-23.963214, -46.28054]}
          zoom={13}
          style={{ height: '100%', width: '100%' }}
        >
          <TileLayer
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            attribution='&copy; OpenStreetMap'
          />
          
          {points.length > 0 && (
            <Polyline 
              positions={points.map(p => [p.latitude, p.longitude])}
              color="#007bff"
              weight={3}
            />
          )}
          
          {currentPoint && (
            <Marker position={[currentPoint.latitude, currentPoint.longitude]}>
              {/* Seu componente CarSprite aqui */}
            </Marker>
          )}
        </MapContainer>
      </div>

      <footer style={{ padding: '1rem', background: '#f5f5f5' }}>
        <p>Placa: {vehicle?.plate?.trim()} | Velocidade: {currentPoint?.speed || 0} km/h</p>
      </footer>
    </div>
  );
};

export default App;
